а я гадав, що ти вода, | (7)','["pisni.org.ua", "cat:philosophic", "Філософські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_310467'), datetime('now')),datetime('now'));
